#include <bits/stdc++.h>
#define int long long
using namespace std;
struct edge {
	int t, w, n;
} e[ 5000005 ];
bool bl[ 2 ][ 2000005 ];
int now[ 2000005 ];
int ret[ 2000005 ];
int h[ 2000005 ], m;
int x, y, xx, yy, s, t, u, v, l, r;
int tmp, rem, res;
char c;
signed main() {
	r = tmp = 2;
	cin >> t >> s;
	cin >> x >> y >> xx >> yy;
	for ( int i = 1 ; i <= 2 * s + 1 ; i++ ) {
		for ( int j = 1 ; j <= ( ( i & 1 ) ? t : ( ( t * 2 ) | 1 ) ) ; j++ ) {
			cin >> c;
			if ( 'n' == c )
				continue;
			if ( i & 1 ) {
				u = ( t + 1 ) * ( i / 2 ) + j;
				v = u + 1;
			} else {
				u = ( t + 1 ) * ( i / 2 ) + ( j / 2 ) + ( 1 & j );
				v = u - ( 1 & j ) - t;
			}
			e[ ++m ].w = !( c == 'w' );
			e[ m ].t = u;
			e[ m ].n = h[ v ];
			h[ v ] = m;
			e[ ++m ].w = !( c == 'w' );
			e[ m ].t = v;
			e[ m ].n = h[ u ];
			h[ u ] = m;
		}
	}
	now[ 2 ] = now[ 1 ] = x + 1 + ( t + 1 ) * y;
	ret[ 1 ] = 0;
	res = 0;
	rem = xx + 1 + (t + 1) * yy;
	ret[ 2 ] = l = 1;
	bl[ 1 ][ now[ 1 ] ] = 1;
	bl[ 0 ][ now[ 1 ] ] = 1;
	while( r >= l) {
		if (rem == now[ l ]) break;
		for (int i = h[ now[ l ] ] ; i ; i = e[i].n)
			if( e[ i ].w != ret[ l ] ) {
				v = e[ i ].t;
				if( bl[ e[ i ].w ][ v ] == 0) now[++r] = v, bl[e[i].w][v] = 1, ret[r] = e[i].w;
			}
		l++;
		if ( tmp < l ) {
			res++;
			tmp = r;
		}
	}
	cout << res;
	return 0;
}
